class Solution {
    public int numPairsDivisibleBy60(int[] time) {
        int[] count = new int[60];
        int pairs = 0;
        for (int t : time) {
            int remainder = t % 60;
            pairs += count[(60 - remainder) % 60];
            count[remainder]++;
        }
        return pairs;
    }
}
efficiency: HIGH
time complexity: O(n)
space complexity: O(1)
energy implications: LOW
explanation: Utilizes a frequency count array to track song durations modulo 60, pairing complementary remainders to achieve divisibility by 60.
